### The 'use client' Directive

Add `'use client'` at the top of a file to mark it as a Client Component. This tells Next.js to send JavaScript to the browser:

```jsx
'use client';

import { useState } from 'react';

export default function Counter() {
  const [count, setCount] = useState(0);

  return (
    <div>
      <p>Count: {count}</p>
      <button onClick={() => setCount(c => c + 1)}>Increment</button>
    </div>
  );
}
```

### When to Use Client Components

Use Client Components when you need:

- **Interactivity**: onClick, onChange, onSubmit
- **State**: useState, useReducer
- **Effects**: useEffect, useLayoutEffect
- **Browser APIs**: localStorage, window, document
- **Custom hooks that use state/effects**
- **Context**: React Context providers
- **Event listeners**

### What Client Components Can Do

| Feature | Available |
|---------|-----------|
| useState, useEffect | Yes |
| Browser APIs | Yes |
| Event handlers | Yes |
| Context | Yes |
| Server-side data (props from server) | Yes |
| Database access directly | No |
| File system access | No |

### Client Components Can Import Server Components

Pass Server Components as children to Client Components:

```jsx
'use client';

export default function ClientWrapper({ children }) {
  const [show, setShow] = useState(false);

  return (
    <div>
      <button onClick={() => setShow(!show)}>Toggle</button>
      {show && children} {/* children can be Server Components */}
    </div>
  );
}

// Server Component using the client wrapper
// app/page.js
import ClientWrapper from './ClientWrapper';
import ServerComponent from './ServerComponent';

export default function Home() {
  return (
    <ClientWrapper>
      <ServerComponent /> {/* Stays on server */}
    </ClientWrapper>
  );
}
```

### Hooks Compatibility

Client Components support all React hooks:

```jsx
'use client';

import { useState, useEffect, useContext, useRef, useMemo, useCallback } from 'react';
import { useRouter } from 'next/navigation';

export default function SearchBar() {
  const router = useRouter();
  const inputRef = useRef(null);
  const [query, setQuery] = useState('');

  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  const handleSearch = useCallback((e) => {
    e.preventDefault();
    router.push(`/search?q=${query}`);
  }, [query, router]);

  return (
    <form onSubmit={handleSearch}>
      <input ref={inputRef} value={query} onChange={e => setQuery(e.target.value)} />
      <button type="submit">Search</button>
    </form>
  );
}
```

codeExample:
'use client';

import { useState, useEffect } from 'react';

export default function Clock() {
  const [time, setTime] = useState(new Date());

  useEffect(() => {
    const interval = setInterval(() => {
      setTime(new Date());
    }, 1000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div>
      <h2>Current Time</h2>
      <p>{time.toLocaleTimeString()}</p>
    </div>
  );
}
